import React from "react";
import VideoPanel from "../components/videoPanel";
import BarraHorizontal from "../components/barraHorizontal";
import ContenedorLateral from "../components/contenedorLateral";
import ImagenInteractiva from "../components/imagenInteractiva";
import CarruselImagenes from "../components/carruselImagenes";

const HomePage = () => {
  return (
    <div className="w-full min-h-screen bg-background flex flex-col">
      {/* Video Principal - Responsive height */}
      <section className="relative">
        <VideoPanel height="clamp(40vh, 61.8vh, 80vh)">
          <video 
            className="w-full h-full object-cover" 
            src="/media/homePage/video.webm" 
            autoPlay 
            muted 
            loop 
          />
        </VideoPanel>
      </section>

      {/* Espaciado responsive entre secciones */}
      <div className="h-8 md:h-12 lg:h-16"></div>

      {/* Barra de Separación - Empresas que Forjaron el País - VERSIÓN MEJORADA */}
      <section className="relative overflow-hidden">
        <div 
          className="relative w-full flex items-center justify-center py-6 md:py-8 lg:py-10"
          style={{ 
            backgroundColor: '#072D42',
            backgroundImage: 'linear-gradient(135deg, #072D42 0%, #051c2c 100%)'
          }}
        >
          {/* Elementos decorativos de luz/energía */}
          <div className="absolute top-0 left-0 w-20 h-full bg-gradient-to-r from-[#072D42] to-transparent opacity-70"></div>
          <div className="absolute top-0 right-0 w-20 h-full bg-gradient-to-l from-[#072D42] to-transparent opacity-70"></div>
          
          {/* Efecto de destello central */}
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="w-1/3 h-1 blur-md opacity-20" style={{ backgroundColor: '#F29E38' }}></div>
          </div>
          
          <div className="relative z-10 text-center px-4">
            <h2 
              className="text-2xl md:text-3xl lg:text-4xl xl:text-5xl font-bold tracking-wide uppercase"
              style={{ 
                color: '#F4E9D7',
                textShadow: '0 0 15px rgba(242, 158, 56, 0.3), 0 0 5px rgba(255, 255, 255, 0.1)',
                letterSpacing: '0.15em'
              }}
            >
              EMPRESAS QUE <span style={{ color: '#F29E38' }}>FORJARON</span> EL PAÍS
            </h2>
            
            {/* Línea decorativa inferior */}
            <div className="flex justify-center mt-4 md:mt-5 lg:mt-6">
              <div 
                className="h-1 w-16 md:w-20 rounded-full"
                style={{ backgroundColor: '#F29E38' }}
              ></div>
              <div 
                className="h-1 w-4 md:w-6 mx-2 rounded-full"
                style={{ backgroundColor: '#F4E9D7' }}
              ></div>
              <div 
                className="h-1 w-16 md:w-20 rounded-full"
                style={{ backgroundColor: '#F29E38' }}
              ></div>
            </div>
          </div>
          
          {/* Elementos decorativos de esquina */}
          <div className="absolute top-3 left-3 md:top-4 md:left-4 w-4 h-4 border-t-2 border-l-2" style={{ borderColor: '#F29E38' }}></div>
          <div className="absolute top-3 right-3 md:top-4 md:right-4 w-4 h-4 border-t-2 border-r-2" style={{ borderColor: '#F29E38' }}></div>
          <div className="absolute bottom-3 left-3 md:bottom-4 md:left-4 w-4 h-4 border-b-2 border-l-2" style={{ borderColor: '#F29E38' }}></div>
          <div className="absolute bottom-3 right-3 md:bottom-4 md:right-4 w-4 h-4 border-b-2 border-r-2" style={{ borderColor: '#F29E38' }}></div>
        </div>
      </section>

      {/* Espaciado responsive entre secciones */}
      <div className="h-8 md:h-12 lg:h-16"></div>

      {/* Sección Principal de Contenido - Layout áureo perfectamente alineado */}
      <section className="w-full px-4 md:px-8 lg:px-16 xl:px-32">
        <div className="max-w-[1440px] mx-auto">
          <div className="flex flex-col lg:flex-row items-start" style={{ gap: 'clamp(2rem, 6.18vw, 4rem)' }}>
            {/* Panel Interactivo Izquierdo - Proporción áurea 30.9% (agrandado) */}
            <div className="w-full lg:w-[30.9%] flex justify-center lg:justify-start" style={{ marginTop: 'clamp(2rem, 6.18vh, 4rem)' }}>
              <div className="w-full max-w-[400px] lg:max-w-none">
                <ImagenInteractiva
                  ancho="100%"
                  imagenDefault="/media/homePage/defaultImage.png"
                  items={[
                    {
                      icono: "/media/homePage/lightIcon.png",
                      subtitulo: "INNOVACIÓN",
                      imagen: "/media/homePage/c1.webp",
                      texto: "Más de cuatro décadas impulsando el cambio constante, reinventándonos para anticipar el futuro y ofrecer soluciones que transforman industrias y vidas.",
                    },
                    {
                      icono: "/media/homePage/recicleIcon.png",
                      subtitulo: "SOSTENIBILIDAD",
                      imagen: "/media/homePage/c2.webp",
                      texto: "Creciendo junto a nuestro entorno, adaptándonos y protegiendo recursos para garantizar un legado duradero y un impacto positivo en las generaciones futuras.",
                    },
                    {
                      icono: "/media/homePage/secureIcon.png",
                      subtitulo: "CONFIANZA",
                      imagen: "/media/homePage/c3.jpg",
                      texto: "Construimos relaciones sólidas y duraderas, basadas en la transparencia y el compromiso, que han sido el pilar para acompañar a nuestros clientes por más de cuatro décadas.",
                    },
                    {
                      icono: "/media/homePage/awardIcon.png",
                      subtitulo: "EXCELENCIA",
                      imagen: "/media/homePage/c4.jpg",
                      texto: "Más de 40 años superando expectativas y estableciendo estándares de calidad, dedicados a la perfección en cada producto y servicio que ofrecemos.",
                    },
                  ]}
                />
              </div>
            </div>

            {/* Contenedor Lateral Derecho - Proporción áurea 69.1% pegado al lateral derecho */}
            <div className="w-full lg:w-[69.1%] flex justify-center lg:justify-end">
              <div className="w-full max-w-[700px] lg:max-w-none">
                <ContenedorLateral
                  subtitulo="SEMANA DE ACTIVIDADES"
                  imagen="/media/homePage/work.jpeg"
                  ancho="100%"
                  alto="clamp(35vh, 42vh, 55vh)"
                  ovaloRedondez="20px"
                  cuadroRedondez="10px"
                />
              </div>
            </div>
          </div>
        </div>
      </section>
      
      {/* Espaciado responsive entre secciones */}
      <div className="h-8 md:h-12 lg:h-16"></div>
      
      {/* Barra de Separación - Recorridos de +40 Años */}
      <section className="relative">
        <BarraHorizontal
          texto="RECORRIDOS DE +40 AÑOS"
          height="clamp(3vh, 6.18vh, 8vh)"
          margenHorizontal="clamp(10vw, 19.1vw, 25vw)"
          imagen="/media/homePage/barra.png"
        />
      </section>

      {/* Espaciado responsive entre secciones */}
      <div className="h-8 md:h-12 lg:h-16"></div>

      {/* Carrusel de Imágenes - Responsive padding */}
      <section className="w-full bg-surface py-8 md:py-12 lg:py-16">
        <div className="px-4 md:px-8 lg:px-16 xl:px-32">
          <div className="max-w-[1440px] mx-auto">
            <CarruselImagenes
              altura={400}
              filas={3}
              backendUrl="http://localhost:3001"
            />
          </div>
        </div>
      </section>
    </div>
  );
};

export default HomePage;
